using McpHttpServer.Tools;
using McpHttpServer.Resources;

var builder = WebApplication.CreateBuilder(args);

// Register the MCP server with HTTP (Streamable HTTP) transport.
// WithTools / WithResources scan the given types for [McpServerTool]
// and [McpServerResource] attributes.
builder.Services
    .AddMcpServer()
    .WithHttpTransport()
    .WithTools<DevTools>()
    .WithResources<ConfigResource>();

var app = builder.Build();

// Health-check endpoint (useful for load-balancers / k8s probes)
app.MapGet("/health", () => Results.Ok("healthy"));

// Mount the MCP Streamable-HTTP endpoint at /mcp
app.MapMcp();

app.Run();

